//! Modern-playable cards that complement the BRG combo and Goryo's
//! Vengeance demo decks. These are *new* card factories, distinct from the
//! existing `creatures.rs` / `lands.rs` / `spells.rs` set. Most ride
//! existing engine primitives; some batches ship small reusable primitives
//! alongside their cards.
//!
//! Cards in this file are tracked in `DECK_FEATURES.md` under the **Modern
//! supplement** section.

use crate::card::{
    ActivatedAbility, Adventure, ArtifactSubtype, CardDefinition, CardType, CreatureType, Effect,
    Keyword, LandType, SelectionRequirement, Selector, SoulbondBonus, SplitCard, SplitHalf,
    Subtypes, Supertype, TokenDefinition, TriggeredAbility, Value, WardCost,
};
use crate::card::{CounterType, DynamicPt, EventKind, EventScope, EventSpec};
use crate::card::{StaticAbility, StaticEffect};
use crate::effect::shortcut::{
    each_your_creature, etb, etb_explore, explore, investigate, on_dies, target_filtered,
};
use crate::effect::{Duration, ManaPayload, Predicate, PlayerRef, ZoneDest};
use crate::mana::{Color, ManaCost, ManaSymbol, b, colorless, cost, g, generic, r, u, w, x};

// ── Cantrips & card selection ────────────────────────────────────────────────

/// Ponder — {U} Sorcery. Look at the top three cards of your library, then
/// put them back in any order, then draw a card. (The "you may shuffle" rider
/// is dropped.)
pub fn ponder() -> CardDefinition {
    CardDefinition {
        name: "Ponder",
        cost: cost(&[u()]),
        card_types: vec![CardType::Sorcery],
        effect: Effect::Seq(vec![
            Effect::RearrangeTop { who: PlayerRef::You, amount: Value::Const(3) },
            Effect::Draw { who: Selector::You, amount: Value::Const(1) },
        ]),
        ..Default::default()
    }
}

/// Index — {U} Sorcery. Look at the top five cards of your library, then put
/// them back in any order.
pub fn index() -> CardDefinition {
    CardDefinition {
        name: "Index",
        cost: cost(&[u()]),
        card_types: vec![CardType::Sorcery],
        effect: Effect::RearrangeTop { who: PlayerRef::You, amount: Value::Const(5) },
        ..Default::default()
    }
}

/// Spire Owl — {1}{U} 1/1 Bird with flying. ETB: look at the top four cards
/// of your library, then put them back in any order.
pub fn spire_owl() -> CardDefinition {
    owl_rearranger("Spire Owl")
}

/// Sage Owl — {1}{U} 1/1 Bird with flying. ETB: look at the top four cards of
/// your library, then put them back in any order.
pub fn sage_owl() -> CardDefinition {
    owl_rearranger("Sage Owl")
}

fn owl_rearranger(name: &'static str) -> CardDefinition {
    CardDefinition {
        name,
        cost: cost(&[generic(1), u()]),
        card_types: vec![CardType::Creature],
        subtypes: Subtypes { creature_types: vec![CreatureType::Bird], ..Default::default() },
        power: 1,
        toughness: 1,
        keywords: vec![Keyword::Flying],
        triggered_abilities: vec![etb(Effect::RearrangeTop {
            who: PlayerRef::You,
            amount: Value::Const(4),
        })],
        ..Default::default()
    }
}

/// Manamorphose — {1}{R/G} Instant. Add two mana in any combination of
/// colors. Draw a card.
///
/// The `{R/G}` pip is a real `ManaSymbol::Hybrid(Red, Green)`, payable
/// with either red or green.
pub fn manamorphose() -> CardDefinition {
    CardDefinition {
        name: "Manamorphose",
        cost: cost(&[generic(1), crate::mana::hybrid(Color::Red, Color::Green)]),
        card_types: vec![CardType::Instant],
        effect: Effect::Seq(vec![
            Effect::AddMana {
                who: PlayerRef::You,
                pool: ManaPayload::AnyColors(Value::Const(2)),
            },
            Effect::Draw { who: Selector::You, amount: Value::Const(1) },
        ]),
        ..Default::default()
    }
}

/// Sleight of Hand — {U} Sorcery. Look at the top two cards of your library,
/// put one into your hand, the other on the bottom.
///
/// Approximation: `Scry 1 + Draw 1` — close enough to "look at 2, take the
/// better one" since Scry can put the unwanted card on the bottom before the
/// draw resolves (slightly worse than the real card's view of two).
pub fn sleight_of_hand() -> CardDefinition {
    CardDefinition {
        name: "Sleight of Hand",
        cost: cost(&[u()]),
        card_types: vec![CardType::Sorcery],
        effect: Effect::Seq(vec![
            Effect::Scry { who: PlayerRef::You, amount: Value::Const(1) },
            Effect::Draw { who: Selector::You, amount: Value::Const(1) },
        ]),
        ..Default::default()
    }
}

// ── Discard, draw-for-life, mill ─────────────────────────────────────────────

/// Faithless Looting — {R} Sorcery. Draw two cards, then discard two cards.
/// Flashback {2}{R}.
pub fn faithless_looting() -> CardDefinition {
    let flashback_cost = ManaCost {
        symbols: vec![ManaSymbol::Generic(2), ManaSymbol::Colored(Color::Red)],
    };
    CardDefinition {
        name: "Faithless Looting",
        cost: cost(&[r()]),
        card_types: vec![CardType::Sorcery],
        keywords: vec![Keyword::Flashback(flashback_cost)],
        effect: Effect::Seq(vec![
            Effect::Draw { who: Selector::You, amount: Value::Const(2) },
            Effect::Discard {
                who: Selector::You,
                amount: Value::Const(2),
                random: false,
            },
        ]),
        ..Default::default()
    }
}

/// Sign in Blood — {B}{B} Sorcery. Target player draws two cards and loses
/// 2 life.
///
/// Targets any player via `target_filtered(Player)`; both effects run
/// against `Selector::Player(PlayerRef::Target(0))` (same pattern Thought
/// Scour and Vapor Snag already use). Auto-targeting picks the caster
/// when no target is supplied, so the BRG demo's "self-cantrip" line
/// keeps working.
pub fn sign_in_blood() -> CardDefinition {
    CardDefinition {
        name: "Sign in Blood",
        cost: cost(&[b(), b()]),
        card_types: vec![CardType::Sorcery],
        effect: Effect::Seq(vec![
            Effect::Draw {
                who: target_filtered(SelectionRequirement::Player),
                amount: Value::Const(2),
            },
            Effect::LoseLife {
                who: Selector::Player(PlayerRef::Target(0)),
                amount: Value::Const(2),
            },
        ]),
        ..Default::default()
    }
}

/// Night's Whisper — {1}{B} Sorcery. Draw two cards, lose 2 life.
pub fn nights_whisper() -> CardDefinition {
    CardDefinition {
        name: "Night's Whisper",
        cost: cost(&[generic(1), b()]),
        card_types: vec![CardType::Sorcery],
        effect: Effect::Seq(vec![
            Effect::Draw { who: Selector::You, amount: Value::Const(2) },
            Effect::LoseLife { who: Selector::You, amount: Value::Const(2) },
        ]),
        ..Default::default()
    }
}

/// Duress — {B} Sorcery. Target opponent reveals their hand. You choose a
/// noncreature, nonland card. They discard it.
pub fn duress() -> CardDefinition {
    CardDefinition {
        name: "Duress",
        cost: cost(&[b()]),
        card_types: vec![CardType::Sorcery],
        effect: Effect::DiscardChosen {
            from: Selector::Player(PlayerRef::EachOpponent),
            count: Value::Const(1),
            filter: SelectionRequirement::Nonland.and(SelectionRequirement::Noncreature),
        },
        ..Default::default()
    }
}

