/// Saheeli Rai — {1}{U}{R} Legendary Planeswalker — Saheeli. 3 loyalty.
/// **+1**: Scry 1. Saheeli Rai deals 1 damage to each opponent and each
/// planeswalker an opponent controls.
/// **-2**: Create a token that's a copy of target artifact or creature
/// you control, except it has haste. Exile it at the beginning of the
/// next end step.
/// **-7**: Search your library for up to three artifact cards with
/// different names, put them onto the battlefield, then shuffle.
pub fn saheeli_rai() -> CardDefinition {
    use crate::card::{LoyaltyAbility, PlaneswalkerSubtype, Supertype as Sup};
    use crate::effect::{DelayedTriggerKind, Duration};
    let copy_friendly = || Effect::Seq(vec![
        Effect::CreateTokenCopyOf {
            who: PlayerRef::You,
            count: Value::Const(1),
            source: target_filtered(
                SelectionRequirement::Creature
                    .or(SelectionRequirement::Artifact)
                    .and(SelectionRequirement::ControlledByYou),
            ),
            extra_creature_types: vec![],
            override_pt: None,
            non_legendary: false,
        },
        Effect::GrantKeyword {
            what: Selector::LastCreatedToken,
            keyword: crate::card::Keyword::Haste,
            duration: Duration::Permanent,
        },
        Effect::DelayUntil {
            kind: DelayedTriggerKind::NextEndStep,
            body: Box::new(Effect::Exile {
                what: Selector::LastCreatedToken,
            }),
        },
    ]);
    CardDefinition {
        name: "Saheeli Rai",
        cost: cost(&[generic(1), u(), r()]),
        supertypes: vec![Sup::Legendary],
        card_types: vec![CardType::Planeswalker],
        subtypes: Subtypes {
            planeswalker_subtypes: vec![PlaneswalkerSubtype::Saheeli],
            ..Default::default()
        },
        base_loyalty: 3,
        loyalty_abilities: vec![
            LoyaltyAbility {
                x_cost: false,
                loyalty_cost: 1,
                effect: Effect::Seq(vec![
                    Effect::Scry {
                        who: PlayerRef::You,
                        amount: Value::Const(1),
                    },
                    Effect::DealDamage {
                        to: Selector::Player(PlayerRef::EachOpponent),
                        amount: Value::Const(1),
                    },
                    // "…and each planeswalker they control" (CR 120.3c — the
                    // damage removes a loyalty counter from each).
                    Effect::DealDamage {
                        to: Selector::EachPermanent(
                            SelectionRequirement::Planeswalker
                                .and(SelectionRequirement::ControlledByOpponent),
                        ),
                        amount: Value::Const(1),
                    },
                ]),
            },
            LoyaltyAbility {
                x_cost: false,
                loyalty_cost: -2,
                effect: copy_friendly(),
            },
            // -7: search up to three artifact cards with different names and
            // put them onto the battlefield. Three sequential searches; the
            // second and third exclude already-fetched names
            // (`NameDiffersFromLastMoved`).
            LoyaltyAbility {
                x_cost: false,
                loyalty_cost: -7,
                effect: Effect::Seq(vec![
                    Effect::Search {
                        who: PlayerRef::You,
                        filter: SelectionRequirement::Artifact,
                        to: ZoneDest::Battlefield {
                            controller: PlayerRef::You,
                            tapped: false,
                        },
                    },
                    Effect::Search {
                        who: PlayerRef::You,
                        filter: SelectionRequirement::Artifact
                            .and(SelectionRequirement::NameDiffersFromLastMoved),
                        to: ZoneDest::Battlefield {
                            controller: PlayerRef::You,
                            tapped: false,
                        },
                    },
                    Effect::Search {
                        who: PlayerRef::You,
                        filter: SelectionRequirement::Artifact
                            .and(SelectionRequirement::NameDiffersFromLastMoved),
                        to: ZoneDest::Battlefield {
                            controller: PlayerRef::You,
                            tapped: false,
                        },
                    },
                ]),
            },
        ],
        ..Default::default()
    }
}

