/// Geyadrone Dihada — {2}{B}{R} Legendary Planeswalker — Dihada.
/// 3 loyalty.
/// **+1**: Each opponent loses 1 life and you draw a card. Then if you
/// have less life than an opponent, this PW's loyalty is reset to its
/// starting value.
/// **-3**: Gain control of target creature or planeswalker until end of
/// turn. Untap it. It gains haste until end of turn.
/// **-7**: Ult — each opponent loses half their life, rounded up.
///
/// The +1's "if you have less life than an opponent, reset loyalty to its
/// starting value (3)" rider rides `Effect::SetLoyalty` gated on
/// `Predicate::PlayerHasLessLifeThanOpponent`. The -3 GainControl + Untap +
/// Haste is the Threaten-style play pattern; the -7 ult is faithful via
/// `Effect::LoseHalfLife`.
pub fn geyadrone_dihada() -> CardDefinition {
    use crate::card::{LoyaltyAbility, PlaneswalkerSubtype, Supertype as Sup};
    use crate::effect::{Duration, Predicate};
    CardDefinition {
        name: "Geyadrone Dihada",
        cost: cost(&[generic(2), b(), r()]),
        supertypes: vec![Sup::Legendary],
        card_types: vec![CardType::Planeswalker],
        subtypes: Subtypes {
            planeswalker_subtypes: vec![PlaneswalkerSubtype::Dihada],
            ..Default::default()
        },
        base_loyalty: 3,
        loyalty_abilities: vec![
            LoyaltyAbility {
                x_cost: false,
                loyalty_cost: 1,
                effect: Effect::Seq(vec![
                    Effect::LoseLife {
                        who: Selector::Player(PlayerRef::EachOpponent),
                        amount: Value::Const(1),
                    },
                    Effect::Draw {
                        who: Selector::You,
                        amount: Value::Const(1),
                    },
                    Effect::If {
                        cond: Predicate::PlayerHasLessLifeThanOpponent { who: PlayerRef::You },
                        then: Box::new(Effect::SetLoyalty {
                            what: Selector::This,
                            value: Value::Const(3),
                        }),
                        else_: Box::new(Effect::Noop),
                    },
                ]),
            },
            LoyaltyAbility {
                x_cost: false,
                loyalty_cost: -3,
                effect: Effect::Seq(vec![
                    Effect::GainControl {
                        what: target_filtered(
                            SelectionRequirement::Creature
                                .or(SelectionRequirement::Planeswalker),
                        ),
                        to: None,
                        duration: Duration::EndOfTurn,
                    },
                    Effect::Untap {
                        what: Selector::Target(0),
                        up_to: None,
                    },
                    Effect::GrantKeyword {
                        what: Selector::Target(0),
                        keyword: crate::card::Keyword::Haste,
                        duration: Duration::EndOfTurn,
                    },
                ]),
            },
            LoyaltyAbility {
                x_cost: false,
                loyalty_cost: -7,
                effect: Effect::LoseHalfLife {
                    who: Selector::Player(PlayerRef::EachOpponent),
                    rounded_up: true,
                },
            },
        ],
        ..Default::default()
    }
}

