/// Golgari Grave-Troll — {X}{B}{B} Creature — Skeleton Troll. 0/0, enters
/// with X +1/+1 counters. Dredge 6. `{T}`, remove four +1/+1 counters:
/// regenerate this creature.
pub fn golgari_grave_troll() -> CardDefinition {
    use crate::card::{ActivatedAbility, CounterType};
    use crate::effect::Predicate;
    CardDefinition {
        name: "Golgari Grave-Troll",
        cost: cost(&[generic(0), b(), b()]),
        card_types: vec![CardType::Creature],
        subtypes: Subtypes {
            creature_types: vec![CreatureType::Skeleton, CreatureType::Troll],
            ..Default::default()
        },
        keywords: vec![Keyword::Dredge(6)],
        enters_with_counters: Some((CounterType::PlusOnePlusOne, Value::XFromCost)),
        // {T}, Remove four +1/+1 counters: Regenerate this creature.
        activated_abilities: vec![ActivatedAbility {
            energy_cost: 0,
            discard_cost: None,
            tap_cost: true,
            condition: Some(Predicate::ValueAtLeast(
                Value::CountersOn {
                    what: Box::new(Selector::This),
                    kind: CounterType::PlusOnePlusOne,
                },
                Value::Const(4),
            )),
            effect: Effect::Seq(vec![
                Effect::RemoveCounter {
                    what: Selector::This,
                    kind: CounterType::PlusOnePlusOne,
                    amount: Value::Const(4),
                },
                Effect::Regenerate { what: Selector::This },
            ]),
            ..Default::default()
        }],
        ..Default::default()
    }
}

/// Rancor — {G} Enchantment — Aura. "Enchant creature. Enchanted creature
/// gets +2/+0 and has trample. When this Aura is put into a graveyard from
/// the battlefield, return it to its owner's hand."
pub fn rancor() -> CardDefinition {
    use crate::effect::ZoneDest;
    CardDefinition {
        name: "Rancor",
        cost: cost(&[g()]),
        card_types: vec![CardType::Enchantment],
        subtypes: Subtypes {
            enchantment_subtypes: vec![crate::card::EnchantmentSubtype::Aura],
            ..Default::default()
        },
        effect: Effect::Attach {
            what: Selector::This,
            to: Selector::TargetFiltered {
                slot: 0,
                filter: SelectionRequirement::Creature,
            },
        },
        equipped_bonus: Some(crate::card::EquipBonus {
            power: 2,
            toughness: 0,
            keywords: vec![Keyword::Trample], scale: None, triggered_abilities: vec![], ..Default::default() }),
        // Self-recursion: leaves battlefield → return from graveyard to hand.
        triggered_abilities: vec![TriggeredAbility {
            event: EventSpec::new(EventKind::PermanentLeavesBattlefield, EventScope::SelfSource),
            effect: Effect::Move {
                what: Selector::This,
                to: ZoneDest::Hand(PlayerRef::OwnerOf(Box::new(Selector::This))),
            },
        }],
        ..Default::default()
    }
}

