/// Magda, Brazen Outlaw — {1}{R}, 2/1 Legendary Dwarf Berserker.
/// Other Dwarves you control get +1/+0. Whenever a Dwarf you control
/// becomes tapped, create a Treasure token. (The five-Treasure sacrifice
/// tutor is omitted.)
pub fn magda_brazen_outlaw() -> CardDefinition {
    use crate::card::{ActivatedAbility, ArtifactSubtype, StaticAbility};
    use crate::effect::{StaticEffect, ZoneDest};
    use crate::game::effects::treasure_token;
    CardDefinition {
        name: "Magda, Brazen Outlaw",
        cost: cost(&[generic(1), r()]),
        supertypes: vec![Supertype::Legendary],
        card_types: vec![CardType::Creature],
        subtypes: Subtypes {
            creature_types: vec![CreatureType::Dwarf, CreatureType::Berserker],
            ..Default::default()
        },
        power: 2,
        toughness: 1,
        static_abilities: vec![StaticAbility {
            description: "Other Dwarves you control get +1/+0.",
            effect: StaticEffect::PumpPT {
                applies_to: Selector::EachPermanent(
                    SelectionRequirement::HasCreatureType(CreatureType::Dwarf)
                        .and(SelectionRequirement::ControlledByYou),
                ),
                power: 1,
                toughness: 0,
            },
        }],
        triggered_abilities: vec![TriggeredAbility {
            event: EventSpec::new(EventKind::Tapped, EventScope::YourControl).with_filter(
                Predicate::EntityMatches {
                    what: Selector::TriggerSource,
                    filter: SelectionRequirement::HasCreatureType(CreatureType::Dwarf),
                },
            ),
            effect: Effect::CreateToken {
                who: PlayerRef::You,
                count: Value::Const(1),
                definition: treasure_token(),
            },
        }],
        // Sacrifice five Treasures: search your library for an artifact or
        // Dragon card, put it onto the battlefield, then shuffle.
        activated_abilities: vec![ActivatedAbility {
            energy_cost: 0,
            discard_cost: None,
            sac_other_filter: Some((
                SelectionRequirement::Artifact
                    .and(SelectionRequirement::HasArtifactSubtype(ArtifactSubtype::Treasure)),
                5,
            )),
            effect: Effect::Search {
                who: PlayerRef::You,
                filter: SelectionRequirement::Artifact
                    .or(SelectionRequirement::HasCreatureType(CreatureType::Dragon)),
                to: ZoneDest::Battlefield { controller: PlayerRef::You, tapped: false },
            },
            ..Default::default()
        }],
        ..Default::default()
    }
}

