/// Enduring Innocence — {W}{W}{W} Enchantment Creature — Glimmer. 2/1
/// Lifelink. Draw a card when a nontoken creature you control enters; when it
/// dies it returns as a noncreature enchantment (`ReturnSelfAsEnchantment`).
pub fn enduring_innocence() -> CardDefinition {
    CardDefinition {
        name: "Enduring Innocence",
        cost: cost(&[w(), w(), w()]),
        card_types: vec![CardType::Enchantment, CardType::Creature],
        subtypes: Subtypes {
            creature_types: vec![CreatureType::Glimmer],
            ..Default::default()
        },
        power: 2,
        toughness: 1,
        keywords: vec![Keyword::Lifelink],
        triggered_abilities: vec![
            TriggeredAbility {
                event: EventSpec::new(
                    EventKind::EntersBattlefield,
                    EventScope::AnotherOfYours,
                )
                .with_filter(Predicate::EntityMatches {
                    what: Selector::TriggerSource,
                    filter: SelectionRequirement::Creature
                        .and(SelectionRequirement::NotToken),
                }),
                effect: Effect::Draw {
                    who: Selector::You,
                    amount: Value::Const(1),
                },
            },
            // "When this dies, if it was a creature, return it to the
            // battlefield. It's an enchantment." (Enduring cycle.)
            crate::effect::shortcut::on_dies(Effect::ReturnSelfAsEnchantment),
        ],
        ..Default::default()
    }
}

