/// Thundertrap Trainer — {1}{U} 1/2 Otter Wizard. Offspring {4} (CR 702.166).
/// ETB: look at the top four cards, put any noncreature, nonland cards among
/// them into your hand, rest on the bottom in a random order. ("any number" is
/// take-all-matching rather than "up to one".)
pub fn thundertrap_trainer() -> CardDefinition {
    use crate::effect::shortcut::etb;
    CardDefinition {
        name: "Thundertrap Trainer",
        cost: cost(&[generic(1), u()]),
        card_types: vec![CardType::Creature],
        subtypes: Subtypes {
            creature_types: vec![CreatureType::Otter, CreatureType::Wizard],
            ..Default::default()
        },
        power: 1,
        toughness: 2,
        keywords: vec![Keyword::Offspring(cost(&[generic(4)]))],
        triggered_abilities: vec![
            // Offspring (CR 702.166): if its cost was paid, mint a 1/1 copy.
            etb(Effect::If {
                cond: Predicate::SpellWasKicked,
                then: Box::new(Effect::CreateTokenCopyOf {
                    who: PlayerRef::You,
                    count: Value::Const(1),
                    source: Selector::This,
                    extra_creature_types: vec![],
                    override_pt: Some((1, 1)),
                    non_legendary: false,
                }),
                else_: Box::new(Effect::Noop),
            }),
            etb(Effect::RevealTopTakeMatchingToHand {
                who: PlayerRef::You,
                count: Value::Const(4),
                filter: SelectionRequirement::Noncreature.and(SelectionRequirement::Nonland),
            }),
        ],
        ..Default::default()
    }
}

/// Corpse Dance — {1}{B}{B} Instant. Buyback {2} (CR 702.27).
/// "Put the top creature card of your graveyard onto the battlefield
/// under your control. Sacrifice it at the beginning of the next end
/// step." Buyback returns the spell to hand instead of the graveyard.
pub fn corpse_dance() -> CardDefinition {
    use crate::card::Keyword;
    use crate::effect::DelayedTriggerKind;
    CardDefinition {
        name: "Corpse Dance",
        cost: cost(&[generic(1), b(), b()]),
        card_types: vec![CardType::Instant],
        keywords: vec![Keyword::Buyback(cost(&[generic(2)]))],
        effect: Effect::Seq(vec![
            Effect::Move {
                what: Selector::take(
                    Selector::CardsInZone {
                        who: PlayerRef::You,
                        zone: crate::card::Zone::Graveyard,
                        filter: SelectionRequirement::Creature,
                    },
                    Value::Const(1),
                ),
                to: ZoneDest::Battlefield {
                    controller: PlayerRef::You,
                    tapped: false,
                },
            },
            Effect::DelayUntil {
                kind: DelayedTriggerKind::NextEndStep,
                body: Box::new(Effect::Sacrifice {
                    who: Selector::You,
                    count: Value::Const(1),
                    filter: SelectionRequirement::Creature,
                }),
            },
        ]),
        ..Default::default()
    }
}

