/// control are all colors and your lands are every basic land type (so they
/// tap for any color). The opening-hand Leyline rider is dropped.
pub fn leyline_of_the_guildpact() -> CardDefinition {
    use crate::card::StaticAbility;
    use crate::effect::StaticEffect;
    CardDefinition {
        name: "Leyline of the Guildpact",
        cost: cost(&[w(), u(), b(), r(), g()]),
        card_types: vec![CardType::Enchantment],
        static_abilities: vec![
            StaticAbility {
                description: "Lands you control are every basic land type.",
                effect: StaticEffect::GrantAllBasicLandTypes {
                    applies_to: Selector::EachPermanent(
                        SelectionRequirement::Land.and(SelectionRequirement::ControlledByYou),
                    ),
                },
            },
            StaticAbility {
                description: "Permanents you control are all colors.",
                effect: StaticEffect::GrantAllColors {
                    applies_to: Selector::EachPermanent(SelectionRequirement::ControlledByYou),
                },
            },
        ],
        ..Default::default()
    }
}

/// Consult the Star Charts — {1}{U} Instant. Kicker {1}{U}. Look at the top X
/// cards of your library (X = lands you control), put one (two if kicked) into
/// your hand, and the rest on the bottom in a random order.
pub fn consult_the_star_charts() -> CardDefinition {
    let look = |take: i32| Effect::LookPickToHand {
        who: PlayerRef::You,
        count: Value::CountOf(Box::new(Selector::EachPermanent(
            SelectionRequirement::Land.and(SelectionRequirement::ControlledByYou),
        ))),
        rest_to_graveyard: false,
        pick_filter: None,
        take: Some(Value::Const(take)),
        to_battlefield: false,
    };
    CardDefinition {
        name: "Consult the Star Charts",
        cost: cost(&[generic(1), u()]),
        card_types: vec![CardType::Instant],
        keywords: vec![Keyword::Kicker(cost(&[generic(1), u()]))],
        effect: Effect::If {
            cond: Predicate::SpellWasKicked,
            then: Box::new(look(2)),
            else_: Box::new(look(1)),
        },
        ..Default::default()
    }
}

/// Power Depot — Artifact Land. Enters tapped, Modular 1. `{T}: Add {C}`
