/// Pyrohemia — {2}{R}{R} Enchantment. At the beginning of the end step, if no
/// creatures are on the battlefield, sacrifice it. {R}: deals 1 damage to each
/// creature and each player. (Red Pestilence.)
pub fn pyrohemia() -> CardDefinition {
    use crate::game::types::TurnStep;
    CardDefinition {
        name: "Pyrohemia",
        cost: cost(&[generic(2), r(), r()]),
        card_types: vec![CardType::Enchantment],
        triggered_abilities: vec![TriggeredAbility {
            event: EventSpec::new(EventKind::StepBegins(TurnStep::End), EventScope::AnyPlayer)
                .with_filter(Predicate::Not(Box::new(Predicate::SelectorExists(
                    Selector::EachPermanent(SelectionRequirement::Creature),
                )))),
            effect: Effect::SacrificeSource,
        }],
        activated_abilities: vec![ActivatedAbility {
            mana_cost: cost(&[r()]),
            effect: Effect::Seq(vec![
                Effect::ForEach {
                    selector: Selector::EachPermanent(SelectionRequirement::Creature),
                    body: Box::new(Effect::DealDamage {
                        to: Selector::TriggerSource,
                        amount: Value::Const(1),
                    }),
                },
                Effect::ForEach {
                    selector: Selector::Player(PlayerRef::EachPlayer),
                    body: Box::new(Effect::DealDamage {
                        to: Selector::TriggerSource,
                        amount: Value::Const(1),
                    }),
                },
            ]),
            ..Default::default()
        }],
        ..Default::default()
    }
}

/// Phlage, Titan of Fire's Fury — {1}{R}{W} Legendary 6/6 Elder Giant.
/// Escape—{R}{R}{W}{W}, exile five other graveyard cards. On enter, sacrifice
/// it unless it escaped. On enter or attack, deal 3 to any target and gain 3.
pub fn phlage_titan_of_fires_fury() -> CardDefinition {
    let bolt = Effect::Seq(vec![
        Effect::DealDamage {
            to: target_filtered(
                SelectionRequirement::Creature
                    .or(SelectionRequirement::Player)
                    .or(SelectionRequirement::Planeswalker),
            ),
            amount: Value::Const(3),
        },
        Effect::GainLife { who: Selector::You, amount: Value::Const(3) },
    ]);
    CardDefinition {
        name: "Phlage, Titan of Fire's Fury",
        cost: cost(&[generic(1), r(), w()]),
        supertypes: vec![Supertype::Legendary],
        card_types: vec![CardType::Creature],
        subtypes: Subtypes {
            creature_types: vec![CreatureType::Elder, CreatureType::Giant],
            ..Default::default()
        },
        power: 6,
        toughness: 6,
        keywords: vec![Keyword::Escape(cost(&[r(), r(), w(), w()]), 5)],
        triggered_abilities: vec![
            etb(Effect::If {
                cond: Predicate::Not(Box::new(Predicate::SourceCastFromEscape)),
                then: Box::new(Effect::SacrificeSource),
                else_: Box::new(Effect::Noop),
            }),
            etb(bolt.clone()),
            crate::effect::shortcut::on_attack(bolt),
        ],
        ..Default::default()
    }
}

