/// Agatha's Soul Cauldron — {2} Legendary Artifact. Creatures you control
/// with +1/+1 counters have all activated abilities of creature cards
/// exiled with this. {T}: Exile target card from a graveyard; if it was a
/// creature card, put a +1/+1 counter on a creature you control. (The
/// any-color-for-creature-abilities clause is dropped.)
pub fn agathas_soul_cauldron() -> CardDefinition {
    use crate::card::ActivatedAbility;
    use crate::effect::{Predicate, StaticAbility, StaticEffect};
    CardDefinition {
        name: "Agatha's Soul Cauldron",
        cost: cost(&[generic(2)]),
        supertypes: vec![Supertype::Legendary],
        card_types: vec![CardType::Artifact],
        static_abilities: vec![StaticAbility {
            description: "Creatures you control with +1/+1 counters on them have all activated abilities of all creature cards exiled with this.",
            effect: StaticEffect::CounteredCreaturesHaveAbilitiesOfExiledWithSource,
        }],
        activated_abilities: vec![ActivatedAbility {
            tap_cost: true,
            effect: Effect::Seq(vec![
                Effect::ExileWithSource { what: Selector::Target(0) },
                Effect::If {
                    cond: Predicate::EntityMatches {
                        what: Selector::Target(0),
                        filter: SelectionRequirement::Creature,
                    },
                    then: Box::new(Effect::AddCounter {
                        what: Selector::LeastToughnessYouControl,
                        kind: CounterType::PlusOnePlusOne,
                        amount: Value::Const(1),
                    }),
                    else_: Box::new(Effect::Noop),
                },
            ]),
            ..Default::default()
        }],
        ..Default::default()
    }
}

/// Mutated Cultist — {2}{B} 1/3 Eldrazi Horror. Devoid, deathtouch. Cast
/// trigger: remove all counters from up to one target permanent; your
/// next spell this turn costs {1} less per counter removed.
pub fn mutated_cultist() -> CardDefinition {
    CardDefinition {
        name: "Mutated Cultist",
        cost: cost(&[generic(2), b()]),
        card_types: vec![CardType::Creature],
        subtypes: Subtypes {
            creature_types: vec![CreatureType::Eldrazi, CreatureType::Horror],
            ..Default::default()
        },
        power: 1,
        toughness: 3,
        keywords: vec![Keyword::Devoid, Keyword::Deathtouch],
        triggered_abilities: vec![TriggeredAbility {
            event: EventSpec::new(EventKind::SpellCast, EventScope::SelfSource),
            effect: Effect::MayDo {
                description: "Remove all counters from up to one target permanent".into(),
                body: Box::new(Effect::RemoveAllCountersDiscountNextSpell {
                    // Targeting a counterless permanent is pointless, so the
                    // filter demands counters (helps auto-targeting too).
                    what: target_filtered(SelectionRequirement::Permanent.and(
                        SelectionRequirement::Not(Box::new(SelectionRequirement::HasNoCounters)),
                    )),
                }),
            },
        }],
        ..Default::default()
    }
}

